import java.util.*;public class Main {    public static void main(String[] args) {       Scanner sc = new Scanner(System.in);       int t=sc.nextInt();       while(t-->0){           int[] arr1 = new int[7];           for(int i=0;i<arr1.length;i++){               arr1[i]=sc.nextInt();           }           int sum=0;           for(int i=0;i<arr1.length;i++){               sum-=arr1[i];           }           arr1[0]=sum+2*arr1[0];           for(int i=1;i<arr1.length;i++){               arr1[i]=Math.max(arr1[i-1],sum+2*arr1[i]);           }          System.out.println(arr1[arr1.length-1]);              }    }}